document.addEventListener("DOMContentLoaded",()=>{"use strict";const e=document.querySelectorAll(".filter-btn"),t=document.querySelectorAll(".client-logo");e.forEach(s=>{s.addEventListener("click",()=>{e.forEach(e=>e.classList.remove("active")),s.classList.add("active");const i=s.getAttribute("data-filter");t.forEach(e=>{"all"===i||e.getAttribute("data-category").includes(i)?(e.classList.remove("hidden-category"),setTimeout(()=>{e.classList.add("visible")},50)):(e.classList.remove("visible"),setTimeout(()=>{e.classList.contains("visible")||e.classList.add("hidden-category")},400))})})});const s=new IntersectionObserver((e,t)=>{e.forEach((e,s)=>{e.isIntersecting&&(setTimeout(()=>{e.target.classList.add("visible")},50*s),t.unobserve(e.target))})},{root:null,rootMargin:"0px",threshold:.1});document.querySelectorAll(".client-logo, .testimonial-block").forEach(e=>s.observe(e))});